import android.content.Context
import android.hardware.biometrics.BiometricManager
import android.os.Build
import androidx.core.content.ContextCompat
import java.util.*

class BiometricAuthHelper(private val context: Context) {

    private var biometricManager =
        BiometricManager.from(context)
    private lateinit var sharedPreferences

    companion object {

        const val TAG_FINGERPRINT = "fingerprint"
        const val TAG_PASSWORD = "<PASSWORD>"
    }

    fun isBiometricEnable(): Boolean? {
        return if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.M) {
            when (biometricManager.canAuthenticate()) {
                BiometricManager.BIOMETRIC_SUCCESS -> true
                else -> false
            }
        } else {
            false
        }
    }

    fun isBiometricAuthEnabled(): Boolean? {

        val sharedPreferences = context?.getSharedPreferences(
            "BiometricAuth", Context.MODE_PRIVATE) ?: return null;
        return sharedPreferences.getBoolean("isBiometricAuthEnabled", false);
    }


    private fun storeBiometricAuthEnabled() {

        val sharedPreferences = context?.getSharedPreferences(
            "BiometricAuth", Context.MODE_PRIVATE) ?: return ;
        with (sharedPreferences.edit()) {

            putBoolean("isBiometricAuthEnabled", true)
            commit()
        }

    }
    fun authenticateUser(callback: () -> Unit): Boolean? {

        val sharedPreferences = context?.getSharedPreferences(
            "BiometricAuth", Context.MODE_PRIVATE) ?: return null;
        when (biometricManager.canAuthenticate()) {

            BiometricManager.BIOMETRIC_SUCCESS -> {

                val key = UUID.randomUUID().toString()
                val prefsEditor = sharedPreferences.edit()
                prefsEditor.putString("key", key);
                prefsEditor.commit();

                val executor = ContextCompat.getMainExecutor(context)
                val promptInfo = BiometricPrompt.PromptInfo.Builder()
                    .setTitle("Biometric Login")
                    .setSubtitle("Use your fingerprint to authenticate.")
                    .setDescription("Please authenticate using finger print.")
                    .setNegativeButtonText("Cancel")
                    .build();

                val biometricPrompt = BiometricPrompt(context, executor, object :
                    BiometricPrompt.AuthenticationCallback() {

                    override fun onAuthenticationSucceeded(
                        result: BiometricPrompt.AuthenticationResult) {

                        callback.invoke()
                        storeBiometricAuthEnabled()
                        prefsEditor.remove("key")
                        prefsEditor.commit();
                    }
                })

                biometricPrompt.authenticate(promptInfo);

            }
            BiometricManager.BIOMETRIC_ERROR_HW_UNAVAILABLE -> {
                return false;
            }
            else -> {
                return true;
            }
        }
    }
}